mapper.select:
SELECT MAC as mac, TIME as time, ROUND(avgMerge(RX_FLOW_AVG),2) as rxFlow, ROUND(avgMerge(RX_PACKETS_AVG),2) as rxPackets, ROUND(avgMerge(TX_PACKETS_AVG),2) as txPackets, ROUND(avgMerge(TX_FLOW_AVG),2) as txFlow, ROUND(avgMerge(RX_DROP_AVG),2) as rxDropCount, ROUND(avgMerge(TX_DROP_AVG),2) as txDropCount FROM AGG_HOST_NIC_FLOW_5M WHERE HOST_ID =${hostId} AND TIME BETWEEN ${startTime} AND ${endTime}
AND MAC =#{mac}
GROUP BY TIME, HOST_ID, HOST_POOL_ID, CLUSTER_ID, MAC ORDER BY TIME ASC
